act_string(_c, '$.system'))) AND CAST(intervalEnd(CASE WHEN fhirpath_text(EquipmentUsed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EquipmentUsed.resource, 'effective')), '{') THEN fhirpath_text(EquipmentUsed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(EquipmentUsed.resource, 'effective'), fhirpath_text(EquipmentUsed.resource, 'effective'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Frailty Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Frailty Diagnosis (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS FrailtyDiagnosis WHERE FrailtyDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(FrailtyDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(FrailtyDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from