),
"CT Colonography Performed" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM "Observation: CT Colonography" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS Colonography WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(Colonography.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Colonography.resource, 'effective')), '{') THEN fhirpath_text(Colonography.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(Colonography.resource, 'effective'), fhirpath_text(Colonography.resource, 'effective'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"Colonoscopy Performed" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Colonoscopy" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS ColonoscopyProcedure WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(ColonoscopyProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ColonoscopyProcedure.resource, 'performed')), '{') THEN fhirpath_text(ColonoscopyProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ColonoscopyProcedure.resource, 'performed'), fhirpath_text(ColonoscopyProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 9.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 9.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 9.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"Fecal Occult Blood Test Performed" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM "Observation: Fecal Occult Blood Test (FOBT)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS FecalOccultResult WHERE fhirpath_text(FecalOccultResult.resource, 'value') IS NOT NULL AND CAST(COALESCE(fhirpath_date(FecalOccultResult.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(FecalOccultResult.resource, 'effectivePeriod'))) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(COALESCE(fhirpath_date(FecalOccultResult.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(FecalOccultResult.resource, 'effectivePeriod'))) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)
),
"Flexible Sigmoidoscopy Performed" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Flexible Sigmoidoscopy" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS FlexibleSigmoidoscopy WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(FlexibleSigmoidoscopy.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FlexibleSigmoidoscopy.resource, 'performed')), '{') THEN fhirpath_text(FlexibleSigmoidoscopy.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(FlexibleSigmoidoscopy.resource, 'performed'), fhirpath_text(FlexibleSigmoidoscopy.resource, 'performed'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"Initial Population" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END BETWEEN 46 AND 75 AND EXISTS (SELECT 1 FROM "AdultOutpatientEncounters.Qualifying Encounters" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS MATERIALIZED (
SELECT * FROM "Initial Population"
),
"Malignant Neoplasm" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Malignant Neoplasm of Colon (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Malignant Neoplasm of Colon (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS ColorectalCancer WHERE CAST(intervalStart(CASE WHEN fhirpath_text(ColorectalCancer.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ColorectalCancer.resource, 'onsetDateTime'), fhirpath_text(ColorectalCancer.resource, 'onsetPeriod.start'), fhirpath_text(ColorectalCancer.resource, 'recordedDate')), fhirpath_text(ColorectalCancer.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ColorectalCancer.resource, 'onsetDateTime'), fhirpath_text(ColorectalCancer.resource, 'onsetPeriod.start'), fhirpath_text(ColorectalCancer.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(ColorectalCancer.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(ColorectalCancer.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(ColorectalCancer.resource, 'onsetDateTime'), fhirpath_text(ColorectalCancer.resource, 'onsetPeriod.start'), fhirpath_text(ColorectalCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ColorectalCancer.resource, 'onsetDateTime'), fhirpath_text(ColorectalCancer.resource, 'onsetPeriod.start'), fhirpath_text(ColorectalCancer.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)
),
"SDE Ethnicity" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Sex"
),
"Stool DNA with FIT Test Performed" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM "Observation: sDNA FIT Test" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS sDNATest WHERE fhirpath_text(sDNATest.resource, 'value') IS NOT NULL AND CAST(COALESCE(fhirpath_date(sDNATest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(sDNATest.resource, 'effectivePeriod'))) AS DATE) >= CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 2.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(COALESCE(fhirpath_date(sDNATest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(sDNATest.resource, 'effectivePeriod'))) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)
),
"Numerator" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Fecal Occult Blood Test Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Stool DNA with FIT Test Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Flexible Sigmoidoscopy Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "CT Colonography Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Colonoscopy Performed" AS sub WHERE sub.patient_id = p.patient_id)
),
"Stratification 1" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END BETWEEN 46 AND 49
),
"Stratification 2" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END BETWEEN 50 AND 75
),
"Total Colectomy Performed" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Total Colectomy" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS Colectomy WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(Colectomy.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Colectomy.resource, 'performed')), '{') THEN fhirpath_text(Colectomy.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(Colectomy.resource, 'performed'), fhirpath_text(Colectomy.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)
),
"Denominator Exclusions" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Malignant Neoplasm" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Total Colectomy Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
)
SELECT p.patient_id, compact_audit(struct_pack(result := CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END, evidence := [])) AS "Initial Population", compact_audit(struct_pack(result := CASE WHEN "Denominator".patient_id IS NOT NULL AND "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END, evidence := [])) AS Denominator, compact_audit(struct_pack(result := CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END, evidence := [])) AS "Denominator Exclusions", compact_audit(struct_pack(result := CASE WHEN "Numerator".patient_id IS NOT NULL AND "Initial Population".patient_id IS NOT NULL AND "Denominator Exclusions".patient_id IS NULL THEN TRUE ELSE FALSE END, evidence := [])) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
